data.content:
**MSTest does not have `Assert.IsGreaterThan` or `Assert.IsInRange`** — those methods don't exist. Here's what's actually available for boundary checks:

| Need | MSTest Approach |
|---|---|
| Exact value | `Assert.AreEqual(expected, actual)` |
| Comparisons | `Assert.IsTrue(actual > threshold, "message")` |
| Exceptions | `Assert.ThrowsException<T>(() => ...)` |
| Floating-point | `Assert.AreEqual(expected, actual, delta)` |

The `delta` overload — `Assert.AreEqual(expected, actual, 0.001)` — is especially important here since `CalculatePercentage` and `NormalizeScore` return `double`.

Example tests for your class:

```csharp
using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();

    // ── CalculatePercentage ──

    [TestMethod]
    public void CalculatePercentage_PerfectScore_Returns100()
    {
        Assert.AreEqual(100.0, _calc.CalculatePercentage(10, 10), 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroCorrect_Returns0()
    {
        Assert.AreEqual(0.0, _calc.CalculatePercentage(0, 10), 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_PartialScore_ReturnsExpected()
    {
        Assert.AreEqual(75.0, _calc.CalculatePercentage(3, 4), 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(11, 10));
    }

    // ── GetGrade boundary tests ──

    [DataTestMethod]
    [DataRow(90.0, "A")]
    [DataRow(100.0, "A")]
    [DataRow(89.999, "B")]
    [DataRow(80.0, "B")]
    [DataRow(79.999, "C")]
    [DataRow(70.0, "C")]
    [DataRow(69.999, "D")]
    [DataRow(60.0, "D")]
    [DataRow(59.999, "F")]
    [DataRow(0.0, "F")]
    public void GetGrade_AtBoundaries_ReturnsExpectedGrade(
        double percentage, string expected)
    {
        Assert.AreEqual(expected, _calc.GetGrade(percentage));
    }

    // ── NormalizeScore ──

    [TestMethod]
    public void NormalizeScore_ExceedsMax_ClampedTo100()
    {
        double result = _calc.NormalizeScore(150, 100);
        Assert.AreEqual(100.0, result, 0.001);
        // No Assert.IsLessThanOrEqual — use Assert.IsTrue instead:
        Assert.IsTrue(result <= 100.0, $"Score {result} should not exceed 100");
    }

    [TestMethod]
    public void NormalizeScore_ZeroScore_Returns0()
    {
        Assert.AreEqual(0.0, _calc.NormalizeScore(0, 50), 0.001);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(-1, 100));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(50, 0));
    }
}
```

**Key takeaways:**
- Use **`Assert.AreEqual(expected, actual, delta)`** for `double` comparisons — never raw `==`
- Use **`Assert.IsTrue(condition, message)`** for range/comparison checks — always include a message since failures otherwise just say "expected true, was false"
- Use **`[DataTestMethod]`/`[DataRow]`** to efficiently test grade boundaries
- If you want richer assertions like `.Should().BeInRange()`, consider adding the **FluentAssertions** NuGet package
